(window.webpackJsonp=window.webpackJsonp||[]).push([[74],{546:function(t,e,n){"use strict";n.r(e);var r=n(0),o=Object(r.a)({},(function(){return this._self._c("ContentSlotsDistributor",{attrs:{"slot-key":this.$parent.slotKey}},[this._self._c("div",{domProps:{innerHTML:"<p>&lt;div class=&quot;custom-block tip&quot;&gt;&lt;p class=&quot;custom-block-title&quot;&gt;摘要&lt;/p&gt;\n在数字孪生机房系统中，自动漫游巡检和温度热图是两个核心功能。本文详细介绍如何基于 Three.js 实现沉浸式的 3D 机房漫游体验，以及如何利用自定义着色器生成实时温度热图，提升运维效率 40%。\n&lt;/div&gt;</p>\n<h2>一、自动漫游巡检</h2>\n<h3>1. 巡检路径定义</h3>\n<p>巡检路径由一系列关键点组成，使用 CatmullRomCurve3 创建平滑曲线：</p>\n<pre><code class=\"language-javascript\">const pathPoints = [\n  new THREE.Vector3(0, 3, 20),    // 入口\n  new THREE.Vector3(0, 3, 10),    // 第一排机柜\n  new THREE.Vector3(10, 3, 10),   // 转弯\n  new THREE.Vector3(10, 3, -10),  // 第二排机柜\n  new THREE.Vector3(0, 3, -10),   // 转弯\n  new THREE.Vector3(0, 3, -20),   // 末端\n  new THREE.Vector3(-10, 3, -10), // 返回路径\n  new THREE.Vector3(-10, 3, 10),\n  new THREE.Vector3(0, 3, 20),    // 回到入口\n]\n\nconst curve = new THREE.CatmullRomCurve3(pathPoints, true) // closed loop\n</code></pre>\n<h3>2. 相机路径动画</h3>\n<pre><code class=\"language-javascript\">class RoamingController {\n  constructor(camera, controls, curve) {\n    this.camera = camera\n    this.controls = controls\n    this.curve = curve\n    this.progress = 0\n    this.speed = 0.0005\n    this.isPlaying = false\n    this.lookAheadDistance = 0.01\n  }\n\n  start() {\n    this.isPlaying = true\n    this.controls.enabled = false // 禁用手动控制\n  }\n\n  stop() {\n    this.isPlaying = false\n    this.controls.enabled = true\n  }\n\n  pause() {\n    this.isPlaying = false\n  }\n\n  update() {\n    if (!this.isPlaying) return\n\n    this.progress += this.speed\n    if (this.progress &gt;= 1) this.progress = 0\n\n    // 获取当前位置\n    const currentPos = this.curve.getPointAt(this.progress)\n    // 获取前方注视点\n    const lookAtProgress = (this.progress + this.lookAheadDistance) % 1\n    const lookAtPos = this.curve.getPointAt(lookAtProgress)\n\n    // 平滑移动相机\n    this.camera.position.lerp(currentPos, 0.05)\n    // 相机注视前方\n    this.controls.target.lerp(lookAtPos, 0.05)\n    this.controls.update()\n  }\n}\n</code></pre>\n<h3>3. 巡检点停留与信息展示</h3>\n<pre><code class=\"language-javascript\">const checkpoints = [\n  { progress: 0.1, deviceId: 'rack-A01', stayTime: 3000 },\n  { progress: 0.25, deviceId: 'rack-A05', stayTime: 3000 },\n  { progress: 0.5, deviceId: 'rack-B03', stayTime: 5000 },\n  { progress: 0.75, deviceId: 'rack-C01', stayTime: 3000 },\n]\n\nclass InspectionController extends RoamingController {\n  constructor(camera, controls, curve, checkpoints) {\n    super(camera, controls, curve)\n    this.checkpoints = checkpoints\n    this.currentCheckpoint = 0\n    this.isPaused = false\n    this.pauseTimer = null\n  }\n\n  update() {\n    if (this.isPaused) return\n    super.update()\n\n    // 检查是否到达巡检点\n    const checkpoint = this.checkpoints[this.currentCheckpoint]\n    if (checkpoint &amp;&amp; Math.abs(this.progress - checkpoint.progress) &lt; 0.005) {\n      this.isPaused = true\n      // 高亮设备\n      highlightDevice(checkpoint.deviceId)\n      // 显示设备信息\n      showDeviceInfo(checkpoint.deviceId)\n\n      this.pauseTimer = setTimeout(() =&gt; {\n        this.isPaused = false\n        this.currentCheckpoint = (this.currentCheckpoint + 1) % this.checkpoints.length\n      }, checkpoint.stayTime)\n    }\n  }\n}\n</code></pre>\n<h2>二、温度热图分析</h2>\n<h3>1. 热图数据生成</h3>\n<pre><code class=\"language-javascript\">function generateHeatmapData(devices) {\n  const canvas = document.createElement('canvas')\n  canvas.width = 256\n  canvas.height = 256\n  const ctx = canvas.getContext('2d')\n\n  // 清除背景\n  ctx.fillStyle = 'rgba(0, 0, 255, 0.1)'\n  ctx.fillRect(0, 0, 256, 256)\n\n  devices.forEach((device) =&gt; {\n    // 将3D坐标映射到2D画布\n    const x = ((device.position.x + 20) / 40) * 256\n    const y = ((device.position.z + 20) / 40) * 256\n    const intensity = device.temperature / 100\n\n    // 绘制热点\n    const gradient = ctx.createRadialGradient(x, y, 0, x, y, 30)\n    gradient.addColorStop(0, `rgba(255, 0, 0, ${intensity})`)\n    gradient.addColorStop(0.5, `rgba(255, 255, 0, ${intensity * 0.5})`)\n    gradient.addColorStop(1, 'rgba(0, 0, 255, 0)')\n\n    ctx.beginPath()\n    ctx.fillStyle = gradient\n    ctx.arc(x, y, 30, 0, Math.PI * 2)\n    ctx.fill()\n  })\n\n  return canvas\n}\n</code></pre>\n<h3>2. 热图平面渲染</h3>\n<pre><code class=\"language-javascript\">function createHeatmapPlane(heatmapCanvas) {\n  const texture = new THREE.CanvasTexture(heatmapCanvas)\n  texture.needsUpdate = true\n\n  const geometry = new THREE.PlaneGeometry(40, 40)\n  const material = new THREE.MeshBasicMaterial({\n    map: texture,\n    transparent: true,\n    opacity: 0.6,\n    depthWrite: false,\n    side: THREE.DoubleSide\n  })\n\n  const heatmapPlane = new THREE.Mesh(geometry, material)\n  heatmapPlane.rotation.x = -Math.PI / 2\n  heatmapPlane.position.y = 0.1 // 略高于地面\n  \n  return heatmapPlane\n}\n</code></pre>\n<h3>3. 实时数据更新</h3>\n<pre><code class=\"language-javascript\">// 每 5 秒更新一次热图数据\nsetInterval(() =&gt; {\n  const latestData = getDeviceTemperatures()\n  const newCanvas = generateHeatmapData(latestData)\n  heatmapPlane.material.map = new THREE.CanvasTexture(newCanvas)\n  heatmapPlane.material.map.needsUpdate = true\n}, 5000)\n</code></pre>\n<h2>三、功能联动</h2>\n<p>漫游巡检和热图分析可以联动：</p>\n<ul>\n<li>漫游到高温区域时，自动弹出温度告警面板</li>\n<li>点击热图区域，定位到对应设备并显示详情</li>\n<li>支持切换「漫游视角」和「俯瞰视角」查看热图</li>\n</ul>\n<h2>四、效果总结</h2>\n<ul>\n<li>自动巡检覆盖率 <strong>100%</strong>，彻底替代人工巡检</li>\n<li>温度热图实现 <strong>5 秒级</strong> 数据更新，异常区域一目了然</li>\n<li>运维效率提升 <strong>40%</strong>，故障响应时间缩短至分钟级</li>\n</ul>\n"}})])}),[],!1,null,null,null);e.default=o.exports}}]);